// This is a workaround for
// https://github.com/jhipster/jhipster-registry/issues/537
// https://github.com/jhipster/generator-jhipster/issues/18533
// The original issue will be fixed with spring cloud 2021.0.4
// https://github.com/spring-cloud/spring-cloud-netflix/issues/3941
package tech.jhipster.registry.config;

import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.boot.context.event.ApplicationReadyEvent;
import org.springframework.context.event.EventListener;
import org.springframework.stereotype.Component;

@Component
public class EurekaWorkaroundConfiguration implements HealthIndicator {

    private boolean applicationIsUp = false;

    @EventListener(ApplicationReadyEvent.class)
    public void onStartup() {
        this.applicationIsUp = true;
    }

    @Override
    public Health health() {
        if (!applicationIsUp) {
            return Health.down().build();
        }
        return Health.up().build();
    }
}

package org.openmetadata.service.apps.bundles.searchIndex;

import java.util.concurrent.ConcurrentHashMap;
import lombok.Getter;
import org.openmetadata.schema.system.StepStats;

@Getter
public class Stats {
  private final StepStats jobStats = new StepStats();
  private final ConcurrentHashMap<String, StepStats> entityStats = new ConcurrentHashMap<>();

  public void updateEntityStats(String entityType, StepStats stats) {
    entityStats.merge(
        entityType,
        stats,
        (existingStats, newStats) -> {
          existingStats.setSuccessRecords(
              existingStats.getSuccessRecords() + newStats.getSuccessRecords());
          existingStats.setFailedRecords(
              existingStats.getFailedRecords() + newStats.getFailedRecords());
          existingStats.setTotalRecords(
              existingStats.getTotalRecords() + newStats.getTotalRecords());
          return existingStats;
        });
  }
}

package org.openmetadata.service.cache;

import java.time.Duration;
import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

public class NoopCacheProvider implements CacheProvider {
  public Optional<String> get(String key) {
    return Optional.empty();
  }

  public void set(String key, String value, Duration ttl) {}

  public boolean setIfAbsent(String key, String value, Duration ttl) {
    return false; // No-op cache always returns false
  }

  public void del(String... keys) {}

  public Optional<String> hget(String key, String field) {
    return Optional.empty();
  }

  public void hset(String key, Map<String, String> fields, Duration ttl) {}

  public void hdel(String key, String... fields) {}

  public boolean available() {
    return false;
  }

  public Map<String, Object> getStats() {
    Map<String, Object> stats = new HashMap<>();
    stats.put("type", "none");
    stats.put("available", false);
    stats.put("message", "Cache is disabled");
    return stats;
  }

  public void close() {}
}

